import React from 'react';
import { useConversation } from './hooks/useConversation';
import ChatBubble from './components/ChatBubble';
import InputArea from './components/InputArea';

function App() {
  // Pulling the logic from your custom hook
  const { messages, isTyping, currentStep, handleUserAnswer } = useConversation();

  return (
  <div className="flex items-center justify-center h-screen bg-[#f0f4f8] p-4">
    <div className="w-full max-w-lg bg-white rounded-3xl shadow-xl overflow-hidden transition-all duration-500 min-h-[400px] flex flex-col">
      
      {/* Subtle Progress Header */}
      <div className="p-6 pb-2 text-center">
        <p className="text-[10px] uppercase tracking-[2px] text-slate-400 font-bold">
          Step {messages.filter(m => m.sender === 'bot').length} of 5
        </p>
      </div>

      {/* Main Content Area - Only shows the LATEST bot message */}
      <div className="flex-1 flex flex-col items-center justify-center p-8 text-center">
        {isTyping ? (
          <div className="animate-pulse text-slate-400 italic text-sm">
            Writing a thought...
          </div>
        ) : (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
            <h2 className="text-2xl font-medium text-slate-800 leading-snug">
              {messages.filter(m => m.sender === 'bot').slice(-1)[0]?.text}
            </h2>
          </div>
        )}
      </div>

      {/* Input Area - Integrated at the bottom */}
      <div className="p-8 pt-0">
        <InputArea 
          currentStep={currentStep} 
          onSendMessage={handleUserAnswer} 
          isTyping={isTyping} 
        />
      </div>
    </div>
  </div>
);
}

export default App;
